# Current run's shared-state dict, so the built-in trackers (tool_calls/agents)
# can reach it from deep inside react()/_one_tool where state isn't a parameter.
# Runs are single-flight (the server serializes via its run lock; the GUI runs
# one worker), so a module-level pointer is safe ACROSS runs; _STATE_LOCK guards
# the appends WITHIN a run (pool / parallel-tool worker threads share one state).
_RUN = {"state": None}
_STATE_LOCK = threading.Lock()


class _RunState:
    """All per-run state, so concurrent runs (different web / gateway sessions) never
    clobber each other. Held in the _CURRENT_RUN ContextVar (built below, once all the
    wrapped globals exist). The process-global _DEFAULT_RUN wraps the module globals,
    so the GUI / CLI / single-session path — and any code not entered through run() —
    behaves EXACTLY as before. run() forks a fresh state per session via .fresh().
    The mutable containers are shared with pool / parallel-tool workers of the SAME
    run (guarded by _STATE_LOCK / _USAGE_LOCK / _HITL_LOCK); the ContextVar is carried
    into those worker threads with contextvars.copy_context()."""
    __slots__ = ("cancel", "stream", "rec", "cost", "usage", "route", "ctx",
                 "images", "confirm", "review", "allow", "trace", "lock",
                 "ws_skills", "session_id")

    def __init__(self, cancel, stream, rec, cost, usage, route, ctx,
                 images, confirm, review, allow, trace, lock, ws_skills,
                 session_id=""):
        self.cancel = cancel; self.stream = stream; self.rec = rec
        self.cost = cost; self.usage = usage; self.route = route; self.ctx = ctx
        self.images = images; self.confirm = confirm; self.review = review
        self.allow = allow; self.trace = trace; self.lock = lock
        self.ws_skills = ws_skills; self.session_id = session_id

    @classmethod
    def fresh(cls, session_id=""):
        """A brand-new, isolated run state (new cancel flag + HITL lock, zeroed
        usage/cost, empty images / HITL-allow / trace / workspace-skills, default
        console HITL handlers)."""
        return cls(
            cancel=threading.Event(), stream={"obj": None}, rec={"state": None},
            cost={"usd": 0.0},
            usage={n: {"input_tokens": 0, "output_tokens": 0, "tool_calls": 0}
                   for n in USAGE},
            route={"choice": None}, ctx={"tokens": 0, "capacity": 0}, images=[],
            confirm={"fn": None}, review={"fn": None}, allow=set(),
            trace={"id": None, "path": None}, lock=threading.Lock(), ws_skills=[],
            session_id=session_id)


def _rs():
    """The current run's state: a per-session _RunState under concurrency, else the
    process-global default that wraps the module globals (identical to pre-refactor
    behaviour for the GUI / CLI / single active session)."""
    return _CURRENT_RUN.get()


class RunCancelled(Exception):
    """Raised at a safe point when the user asked to stop the run."""


class RunDeadline(RunCancelled):
    """Raised when the whole-run wall-clock deadline (CONFIG['max_run_wall_clock_s'])
    is exceeded. Subclasses RunCancelled so fan-out/branch abort handling propagates
    it; the top-level handler returns its [budget] message as the final result."""


class GraphRecursionError(RuntimeError):
    """Raised when a graph-mode run exceeds RECURSION_LIMIT stage transitions —
    usually a Condition loop whose exit expression never becomes true."""


class ToolAborted(RuntimeError):
    """Raised when a tool fails and its error policy is 'raise' — a deliberate,
    non-retryable abort (not a transient error), so stage_retries won't re-run it."""


# Live per-session run states, so the server can Stop a SPECIFIC user's run (its
# own connection) without touching anyone else's. Keyed by session_id; populated
# by run() around a forked run.
_ACTIVE_RUNS: dict = {}
_ACTIVE_RUNS_LOCK = threading.Lock()


def request_cancel(session_id=None) -> None:
    """Ask an in-flight run() to stop. Safe to call from another thread. Also
    force-closes its active LLM stream so a blocked read (e.g. waiting for the
    first token) unblocks at once. With `session_id`, cancels ONLY that session's
    run (concurrent web/gateway users); without, the current/default run (GUI)."""
    st = None
    if session_id:
        with _ACTIVE_RUNS_LOCK:
            st = _ACTIVE_RUNS.get(session_id)
    if st is None:
        st = _rs()
    st.cancel.set()
    s = st.stream.get("obj")
    if s is not None:
        try:
            s.close()
        except Exception:
            pass


def _check_cancel() -> None:
    if _rs().cancel.is_set():
        raise RunCancelled("[cancelled] stopped by the user")


def _run_deadline_check() -> None:
    """Stop the WHOLE run if the optional run-level wall-clock deadline is exceeded.
    Checked between react steps + graph hops (never mid-call). No-op unless
    CONFIG['max_run_wall_clock_s'] is set and this run's start time is recorded."""
    _d = CONFIG.get("max_run_wall_clock_s", 0) or 0
    if not _d:
        return
    _s = _rs().rec.get("run_start")
    if _s is not None and time.monotonic() - _s > _d:
        raise RunDeadline(
            "[budget] Run wall-clock limit exceeded (~%ds) — stopping the run." % int(_d))


