def total_usage() -> dict:
    """Session totals across all agents (USAGE accumulates over the process)."""
    with _USAGE_LOCK:
        return {
            "input_tokens": sum(u["input_tokens"] for u in _rs().usage.values()),
            "output_tokens": sum(u["output_tokens"] for u in _rs().usage.values()),
            "tool_calls": sum(u["tool_calls"] for u in _rs().usage.values()),
        }


