def _run_python_tool_schema():
    """Schema for the built-in run_python tool (opt-in via the agent's code_exec
    flag): run a short Python script in an ISOLATED child process."""
    return {"name": "run_python",
            "description": ("Execute a short Python script in an ISOLATED child "
                "process whose working directory is your workspace folder. Use it "
                "ONLY for ad-hoc analysis the named tools don't cover. pandas, "
                "numpy, scipy and matplotlib (Agg) are importable. Read input "
                "files and WRITE outputs (CSV/PNG) into the current directory. "
                "print() what you want to see — only stdout/stderr is returned."),
            "parameters": {"type": "object",
                           "properties": {"code": {"type": "string",
                               "description": "the full Python source to run"}},
                           "required": ["code"]}}


def _clip_output(out, err):
    """Head+tail of captured streams (never silently drop the head — keep a result
    printed before later log noise)."""
    def hx(s, n=4000):
        s = s or ""
        if len(s) <= n:
            return s
        return (s[:n // 2] + chr(10) + f"...[{len(s) - n} chars elided]..."
                + chr(10) + s[-n // 2:])
    parts = []
    if (out or "").strip():
        parts.append("STDOUT:" + chr(10) + hx(out))
    if (err or "").strip():
        parts.append("STDERR:" + chr(10) + hx(err))
    return chr(10).join(parts) if parts else "(no output)"


def _kill_proc_tree(pid):
    """Kill the child AND its descendants — subprocess timeout only kills the
    direct child, orphaning grandchildren. Windows: taskkill /T /F."""
    import subprocess as _sp
    try:
        if os.name == "nt":
            _sp.run(["taskkill", "/F", "/T", "/PID", str(pid)], capture_output=True)
        else:
            import signal
            try:
                os.killpg(os.getpgid(pid), signal.SIGKILL)
            except Exception:
                os.kill(pid, signal.SIGKILL)
    except Exception:
        pass


def _code_exec_cfg():
    """Configurable code-exec settings (config.json 'code_exec' block)."""
    c = CONFIG.get("code_exec", {}) if "CONFIG" in globals() else {}
    return {"backend": c.get("backend", "subprocess"),   # subprocess | docker | auto
            "timeout": int(c.get("timeout", 30)),
            "memory_mb": int(c.get("memory_mb", 512)),
            "image": c.get("image", "python:3.11-slim")}


def _scrubbed_env():
    """Minimal child env — never inherit secrets/API keys. (config.json on disk is
    still reachable: this is isolation, not secret protection.)"""
    keep = ("SystemRoot", "WINDIR", "TEMP", "TMP", "PATH", "PATHEXT",
            "NUMBER_OF_PROCESSORS", "COMSPEC", "HOMEDRIVE", "HOMEPATH",
            "USERPROFILE", "LANG", "LC_ALL")
    env = {k: os.environ[k] for k in keep if k in os.environ}
    env["PYTHONIOENCODING"] = "utf-8"
    env["MPLBACKEND"] = "Agg"
    env["HTTP_PROXY"] = "http://127.0.0.1:9"      # best-effort net deny (subprocess only)
    env["HTTPS_PROXY"] = "http://127.0.0.1:9"
    env["NO_PROXY"] = ""
    return env


def _docker_available():
    import subprocess
    try:
        return subprocess.run(["docker", "info"], capture_output=True,
                              timeout=6).returncode == 0
    except Exception:
        return False


def _win_job(memory_mb, proc_limit=64):
    """Windows Job Object capping per-process MEMORY + active process count and
    KILLING the whole tree when the handle closes. No admin needed. Returns the
    handle, or None on any failure (caller falls back to taskkill)."""
    if os.name != "nt":
        return None
    try:
        import ctypes
        from ctypes import wintypes
        k32 = ctypes.WinDLL("kernel32", use_last_error=True)
        k32.CreateJobObjectW.restype = wintypes.HANDLE
        k32.CreateJobObjectW.argtypes = [wintypes.LPVOID, wintypes.LPCWSTR]
        k32.SetInformationJobObject.restype = wintypes.BOOL
        k32.SetInformationJobObject.argtypes = [wintypes.HANDLE, ctypes.c_int,
                                                wintypes.LPVOID, wintypes.DWORD]
        k32.CloseHandle.argtypes = [wintypes.HANDLE]
        SIZE_T = ctypes.c_size_t

        class BASIC(ctypes.Structure):
            _fields_ = [("PerProcessUserTimeLimit", ctypes.c_int64),
                        ("PerJobUserTimeLimit", ctypes.c_int64),
                        ("LimitFlags", wintypes.DWORD),
                        ("MinimumWorkingSetSize", SIZE_T),
                        ("MaximumWorkingSetSize", SIZE_T),
                        ("ActiveProcessLimit", wintypes.DWORD),
                        ("Affinity", SIZE_T),
                        ("PriorityClass", wintypes.DWORD),
                        ("SchedulingClass", wintypes.DWORD)]

        class IO(ctypes.Structure):
            _fields_ = [(n, ctypes.c_uint64) for n in
                        ("R", "W", "O", "RT", "WT", "OT")]

        class EXT(ctypes.Structure):
            _fields_ = [("BasicLimitInformation", BASIC), ("IoInfo", IO),
                        ("ProcessMemoryLimit", SIZE_T), ("JobMemoryLimit", SIZE_T),
                        ("PeakProcessMemoryUsed", SIZE_T), ("PeakJobMemoryUsed", SIZE_T)]

        job = k32.CreateJobObjectW(None, None)
        if not job:
            return None
        info = EXT()
        flags = 0x2000                                   # KILL_ON_JOB_CLOSE
        if proc_limit:
            flags |= 0x0008                              # ACTIVE_PROCESS
            info.BasicLimitInformation.ActiveProcessLimit = int(proc_limit)
        if memory_mb and memory_mb > 0:
            flags |= 0x0100                              # PROCESS_MEMORY
            info.ProcessMemoryLimit = int(memory_mb) * 1024 * 1024
        info.BasicLimitInformation.LimitFlags = flags
        if not k32.SetInformationJobObject(job, 9, ctypes.byref(info),
                                           ctypes.sizeof(info)):
            k32.CloseHandle(job)
            return None
        return job
    except Exception:
        return None


def _assign_job(job, pid):
    try:
        import ctypes
        from ctypes import wintypes
        k32 = ctypes.WinDLL("kernel32", use_last_error=True)
        k32.OpenProcess.restype = wintypes.HANDLE
        k32.OpenProcess.argtypes = [wintypes.DWORD, wintypes.BOOL, wintypes.DWORD]
        k32.AssignProcessToJobObject.restype = wintypes.BOOL
        k32.AssignProcessToJobObject.argtypes = [wintypes.HANDLE, wintypes.HANDLE]
        k32.CloseHandle.argtypes = [wintypes.HANDLE]
        h = k32.OpenProcess(0x0100 | 0x0001, False, int(pid))   # SET_QUOTA|TERMINATE
        if not h:
            return False
        ok = bool(k32.AssignProcessToJobObject(job, h))
        k32.CloseHandle(h)
        return ok
    except Exception:
        return False


def _close_handle(job):
    try:
        import ctypes
        from ctypes import wintypes
        k = ctypes.WinDLL("kernel32")
        k.CloseHandle.argtypes = [wintypes.HANDLE]
        k.CloseHandle(job)
    except Exception:
        pass


def _run_subprocess(path, root, timeout, memory_mb):
    """Isolated child python (-I -B), cwd=workspace, scrubbed env, hard timeout.
    On Windows a Job Object caps memory + process count and guarantees the whole
    tree dies; elsewhere we fall back to killpg/taskkill. Returns (rc, out, err);
    rc is None on timeout."""
    import subprocess
    job = _win_job(memory_mb)
    proc = subprocess.Popen(
        [sys.executable, "-I", "-B", path], cwd=root, env=_scrubbed_env(),
        stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True,
        creationflags=getattr(subprocess, "CREATE_NEW_PROCESS_GROUP", 0))
    if job is not None:
        _assign_job(job, proc.pid)
    try:
        out, err = proc.communicate(timeout=timeout)
        return proc.returncode, out, err
    except subprocess.TimeoutExpired:
        if job is not None:
            _close_handle(job); job = None        # KILL_ON_JOB_CLOSE -> whole tree dies
        else:
            _kill_proc_tree(proc.pid)
        try:
            out, err = proc.communicate(timeout=5)
        except Exception:
            out, err = "", ""
        return None, out, err
    finally:
        if job is not None:
            _close_handle(job)


def _run_docker(path, root, timeout, memory_mb, image):
    """True containment when Docker is present (typically a different, Docker-
    capable host): --network=none + cgroup memory/cpu/pids + read-only rootfs,
    only the workspace mounted rw. The IMAGE must already contain whatever the
    script imports (no network to pip-install); default python:3.11-slim is
    stdlib-only — set code_exec.image to a data-science image for pandas etc."""
    import subprocess
    import uuid
    cname = "agentrun_" + uuid.uuid4().hex[:12]
    cmd = ["docker", "run", "--rm", "--name", cname, "--network=none",
           f"--memory={int(memory_mb)}m", "--cpus=2", "--pids-limit=128",
           "--read-only", "--tmpfs", "/tmp:rw,exec,size=256m",
           "-v", f"{root}:/work:rw", "-w", "/work",
           image, "python", "-I", "-B", os.path.basename(path)]
    try:
        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout)
        return proc.returncode, proc.stdout, proc.stderr
    except subprocess.TimeoutExpired:
        try:
            subprocess.run(["docker", "kill", cname], capture_output=True, timeout=10)
        except Exception:
            pass
        return None, "", ""
    except FileNotFoundError:
        return "no-docker", "", ""


def _run_python(args, emit=print):
    """Back the run_python built-in: write the agent's code to a temp .py inside
    the WORKSPACE and run it in an isolated backend (configurable via config.json
    'code_exec': {backend, timeout, memory_mb, image}). Returns captured output.

    Backends: 'subprocess' (default; isolated child python with a Windows Job
    Object capping memory/process-count + tree-kill — ISOLATION, not a security
    boundary: the child still runs with the user's privileges and can read files
    by absolute path incl. config.json), 'docker' (true containment when Docker
    is available — usually a different host), 'auto' (docker if available, else
    subprocess). Always HITL-gated."""
    import tempfile
    code = (args or {}).get("code")
    if not isinstance(code, str) or not code.strip():
        return "[ERROR] run_python needs a non-empty 'code' string."
    folders = get_workspace() if "get_workspace" in globals() else []
    root = folders[0] if folders else None
    if not root or not os.path.isdir(root):
        return ("[ERROR] run_python needs a workspace folder configured. It refuses "
                "to run in the agent's own folder, which holds config.json.")
    cfg = _code_exec_cfg()
    want_docker = cfg["backend"] in ("docker", "auto") and _docker_available()
    note = ""
    if cfg["backend"] == "docker" and not want_docker:
        note = ("[note] backend=docker requested but Docker is unavailable here; "
                "ran in an isolated subprocess instead." + chr(10))
    fd, path = tempfile.mkstemp(suffix=".py", prefix="agent_", dir=root)
    try:
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            f.write(code)
        if want_docker:
            rc, out, err = _run_docker(path, root, cfg["timeout"], cfg["memory_mb"],
                                       cfg["image"])
            label = "docker"
            if rc == "no-docker":                 # docker vanished between check and run
                rc, out, err = _run_subprocess(path, root, cfg["timeout"], cfg["memory_mb"])
                label = "subprocess"
        else:
            rc, out, err = _run_subprocess(path, root, cfg["timeout"], cfg["memory_mb"])
            label = "subprocess"
        if rc is None:
            emit(f"[run_python:{label}] timed out after {cfg['timeout']}s (killed)")
            return (note + f"[ERROR] run_python timed out after {cfg['timeout']}s "
                    f"(killed, backend={label})." + chr(10) + _clip_output(out, err))
        emit(f"[run_python:{label}] exit={rc}")
        return (note + f"exit_code={rc} (backend={label})" + chr(10)
                + _clip_output(out, err) + chr(10)
                + "(files written into the workspace are available to other tools)")
    except Exception as e:    # noqa: BLE001
        return f"[ERROR] run_python failed: {e}"
    finally:
        try:
            os.remove(path)
        except OSError:
            pass              # a timed-out child may still lock the file on Windows


def _match_route(text: str, routes: list, default=None) -> str:
    # delegate to the strict matcher; fall back to the explicit default branch (if
    # set) else the first route when no route name appears (route names are
    # non-empty, so a real match is never falsy).
    return _match_route_strict(text, routes) or default or routes[0]


def _match_route_strict(text: str, routes: list):
    """Like _match_route, but returns None when no route name actually appears in
    `text` (instead of defaulting to the first route). Used in quick-response mode
    so 'no branch named' falls through to a direct answer, not the first worker."""
    low = (text or "").lower()
    for r in sorted(routes, key=len, reverse=True):
        if r.lower() in low:
            return r
    return None


def _extract_route(tool_calls, text, routes, default=None):
    """The routing decision, most-reliable-first: a route_to tool call (enum), else
    a final 'ROUTE: <name>' line, else a substring match, else the default branch
    (if configured) else the first."""
    for tc in (tool_calls or []):
        if tc.get("name") == "route_to":
            a = (tc.get("args") or {}).get("agent")
            return a if a in routes else _match_route(str(a or ""), routes, default)
    for line in reversed((text or "").strip().splitlines()):
        m = re.match(r"\s*ROUTE\s*:\s*(.+)", line, re.IGNORECASE)
        if m:
            return _match_route(m.group(1).strip(), routes, default)
    return _match_route(text or "", routes, default)


def route(name: str, question: str, emit=print) -> str:
    """Ask the router LLM which successor should handle `question`."""
    routes = SUCCESSORS.get(name, [])
    trace_event("stage_start", agent=name, node_kind="router")
    if len(routes) <= 1:
        choice = routes[0] if routes else None
        trace_event("stage_end", agent=name, output=str(choice))
        return choice
    desc = []
    for r in routes:
        spec = AGENTS.get(r, {})
        persona = spec.get("system", "").strip().splitlines()
        line = f"- {r}: {persona[0] if persona else r}"
        tools = spec.get("tools", [])     # surface capability, not just persona
        if tools:                         # wording, so routing matches what a
            line += f" [tools: {', '.join(tools)}]"   # branch can actually do
        desc.append(line)
    system = (AGENTS[name]["system"].strip()
              + "\n\nChoose exactly ONE route for the input by calling the "
                "route_to tool with the chosen agent (or, if you cannot call "
                "tools, reply with only the route name).\n\nRoutes:\n"
              + "\n".join(desc))
    text, tool_calls = llm(name, system,
                           [{"role": "user", "content": question}], emit)
    choice = _extract_route(tool_calls, text, routes,
                            AGENTS.get(name, {}).get("default_route"))
    emit(f"[route] {name} -> {choice}")
    trace_event("route", router=name, choice=choice, routes=routes)
    trace_event("stage_end", agent=name, output=str(choice))
    return choice


def _human_route(name: str, carried: str, emit=print):
    """A ROUTE-mode HITL node: PAUSE and let a human choose which successor runs
    next — the human-driven mirror of route(). Returns (chosen_successor, carried),
    where carried may have been edited by the reviewer. With <=1 successor it's a
    pass-through (no prompt). On timeout, no handler, or an out-of-set answer it
    takes the node's default_route (else the first branch), so an unattended run
    still makes progress."""
    routes = SUCCESSORS.get(name, [])
    trace_event("stage_start", agent=name, node_kind="hitl")
    if len(routes) <= 1:
        _c = routes[0] if routes else None
        trace_event("stage_end", agent=name, output=str(_c))
        return _c, carried
    cfg = HITL_NODES.get(name, {})
    _default = cfg.get("default_route") or routes[0]
    if _default not in routes:
        _default = routes[0]
    emit(f"\n=== [HITL] {name}: awaiting human decision ({len(routes)} options) ===")
    res = human_review(cfg.get("prompt") or f"Choose the next step after '{name}'.",
                       carried, timeout=int(cfg.get("timeout", 0) or 0),
                       on_timeout=_default, choices=list(routes))
    choice = res.get("decision")
    if choice not in routes:                # unknown / legacy handler → default branch
        choice = _default
    _edited = res.get("content")
    if _edited:                             # the reviewer may also edit the payload
        carried = _edited
    emit(f"=== [HITL] {name} -> {choice} ===")
    trace_event("route", router=name, choice=choice, routes=list(routes))
    trace_event("stage_end", agent=name, output=str(choice))
    return choice, carried


def _self_route(name, result, routes, emit=print, quick=False):
    """A self-routing planner picks the next agent from its own output's final
    'ROUTE: <name>' line (falls back to a substring match, then the first route).
    Returns (chosen, output_with_the_ROUTE_line_removed) — no extra LLM call. With
    `quick`, the planner answering without naming a branch (no 'ROUTE: __none__',
    no route name in its 'ROUTE:' line or prose) yields the QUICK_RESPONSE sentinel
    instead of defaulting to the first worker — so a greeting ends with the
    planner's own reply."""
    picked = None
    for line in reversed((result or "").strip().splitlines()):
        m = re.match(r"\s*ROUTE\s*:\s*(.+)", line, re.IGNORECASE)
        if m:
            picked = m.group(1).strip()
            break
    if quick:
        if picked == QUICK_RESPONSE:
            choice = QUICK_RESPONSE                       # explicit decline
        else:                                            # route only if a branch
            choice = (_match_route_strict(picked, routes) if picked  # is named;
                      else _match_route_strict(result, routes)) or QUICK_RESPONSE
    else:
        choice = _match_route(picked if picked else (result or ""), routes)
    cleaned = "\n".join(
        ln for ln in (result or "").splitlines()
        if not re.match(r"\s*ROUTE\s*:", ln, re.IGNORECASE)).strip()
    emit(f"[route] {name} (self) -> {choice}")
    trace_event("route", router=name, choice=choice, routes=routes)
    return choice, (cleaned or result)


# ── shared state: a graph-level scratchpad threaded across stages ────────────
# STATE_SCHEMA is baked from the canvas. This wires the READ path — each stage
# sees the current state in its prompt. Agents updating state (writes) are added
# in a later step.
_TEXT_APPEND_SEP = chr(10) + chr(10)      # blank-line separator between appended chunks


def _append_text(old, new):
    """'append' on a str field = text concatenation (blank-line-joined), NOT
    listifying — so several stages writing one str field accumulate a transcript."""
    old = "" if old is None else str(old)
    new = "" if new is None else str(new)
    return (old + _TEXT_APPEND_SEP + new) if old else new


def _merge_deep(old, new):
    """Recursive dict merge (for record/nested custom types): new keys win, nested
    dicts merge; a type mismatch (or non-dict) lets `new` replace `old`."""
    if isinstance(old, dict) and isinstance(new, dict):
        out = dict(old)
        for k, v in new.items():
            out[k] = _merge_deep(out[k], v) if k in out else v
        return out
    return new


def _extend_list(old, new):
    """'extend' = concatenate lists; a lone value is appended as one element."""
    base = list(old) if isinstance(old, (list, tuple)) else ([] if old is None else [old])
    tail = list(new) if isinstance(new, (list, tuple)) else [new]
    return base + tail


def _upsert_by_key(old, new, key):
    """Merge a list of records by an id field `key` (insert-or-UPDATE): a new
    record whose key matches an existing one is deep-merged INTO it (so a partial
    update keeps the untouched fields); a new key is appended. `new` may be one
    record or a list of them."""
    out = list(old) if isinstance(old, (list, tuple)) else []
    idx = {r.get(key): i for i, r in enumerate(out) if isinstance(r, dict) and key in r}
    for r in (new if isinstance(new, list) else [new]):
        k = r.get(key) if isinstance(r, dict) else None
        if k in idx:
            cur = out[idx[k]]
            out[idx[k]] = _merge_deep(cur, r) if isinstance(cur, dict) and isinstance(r, dict) else r
        else:
            out.append(r)
            if isinstance(r, dict) and key in r:
                idx[k] = len(out) - 1
    return out


_REDUCERS = {
    "overwrite": lambda old, new: new,
    "append": lambda old, new: (list(old) if old else []) + [new],
    "add": lambda old, new: (old or 0) + new,
    "max": lambda old, new: new if old is None else max(old, new),
    "min": lambda old, new: new if old is None else min(old, new),
    # structured policies (records / lists / nested custom types)
    "extend": _extend_list,
    "merge_shallow": lambda old, new: {**(old if isinstance(old, dict) else {}),
                                       **(new if isinstance(new, dict) else {})},
    "merge_deep": _merge_deep,
    # upsert_by_key is applied specially in _apply_state (it needs the merge_key).
}
# Per (reducer, field-type) override: 'append' on a str concatenates instead of
# building a list. Resolved in _apply_state, which knows each field's declared type.
_TYPED_REDUCERS = {("append", "str"): _append_text}

# Custom merge functions (P4 escape hatch): {type_name: merge(old, new)} compiled
# from each custom type's `merge_src`. Empty {} when no type defines one.
_CUSTOM_MERGES = {}


def _new_state(task: str = "") -> dict:
    """A fresh state dict seeded from each field's default (containers copied).
    The read-only built-in `user_input` is seeded with this run's request."""
    out = {}
    for f in STATE_SCHEMA:
        d = f.get("default")
        out[f["name"]] = (list(d) if isinstance(d, list)
                          else dict(d) if isinstance(d, dict) else d)
    if "user_input" in out:
        out["user_input"] = task
    return out


def _apply_state(state: dict, updates: dict, allowed=None) -> dict:
    """Merge {field: value} updates into `state` through each field's reducer.
    Restricts to the `allowed` field names when given; skips unknown fields.
    Returns the {field: new_value} actually written."""
    reducers = {f["name"]: f.get("reducer", "overwrite") for f in STATE_SCHEMA}
    types = {f["name"]: f.get("type", "str") for f in STATE_SCHEMA}
    mkeys = {f["name"]: (f.get("merge_key") or "") for f in STATE_SCHEMA}
    mtypes = {f["name"]: (f.get("merge_type") or "") for f in STATE_SCHEMA}
    allow = set(allowed) if allowed else None
    applied = {}
    for k, v in updates.items():
        if k not in reducers or (allow is not None and k not in allow):
            continue
        try:
            # A model routinely emits a wrong-typed value (e.g. a string into an
            # add/max/min numeric field); skip just that field rather than let a
            # TypeError abort the whole run and discard a good answer.
            red = reducers[k]
            if red == "upsert_by_key":
                new = _upsert_by_key(state.get(k), v, mkeys.get(k) or "id")
            elif red == "custom":
                _cf = _CUSTOM_MERGES.get(mtypes.get(k))
                new = _cf(state.get(k), v) if _cf else v
            else:
                fn = _TYPED_REDUCERS.get((red, types.get(k)),
                                         _REDUCERS.get(red, _REDUCERS["overwrite"]))
                new = fn(state.get(k), v)
        except Exception as e:
            trace_event("state_error", field=k, value=str(v)[:120], error=str(e)[:120])
            continue
        state[k] = new
        applied[k] = new
        # Fan-out branches run on a forked state and record their RAW writes so the
        # join can REPLAY them onto the parent via reducers (exact for every reducer
        # type — no diff heuristics). Only set inside a branch (see _run_branch).
        _cap = _rs().rec.get("capture")
        if _cap is not None:
            _cap.append((k, v))
    return applied


def _track_builtin(field: str, value, agent: str = "") -> None:
    """Append `value` to an auto-maintained built-in field (tool_calls/agents) on
    the current run's state. Framework-managed: bypasses the per-agent writes
    allow-list. Lock-guarded so pool / parallel-tool worker threads (which share
    one run state) don't race. No-op if the field isn't a built-in in this graph."""
    st = _rs().rec.get("state")
    if st is None or field not in _BUILTIN_STATE_NAMES or field not in st:
        return
    with _STATE_LOCK:
        st[field] = _REDUCERS["append"](st.get(field), value)
        snap = dict(st)
    trace_event("state", agent=agent, updates={field: snap[field]}, state=snap)


def _state_preamble(state: dict, reads=None) -> str:
    """A 'Current shared state' block for a stage's prompt. USER fields follow the
    `reads` allow-list (falsy = show all). The auto-maintained built-in fields
    (tool_calls/agents) are shown ONLY when explicitly named in `reads` (opt-in),
    so agents that don't ask for them keep clean prompts. '' when nothing to show."""
    if not STATE_SCHEMA:
        return ""
    keep = set(reads or ())
    names = []
    for f in STATE_SCHEMA:
        nm = f["name"]
        if f.get("builtin"):
            if nm in keep:
                names.append(nm)
        elif not reads or nm in keep:
            names.append(nm)
    if not names:
        return ""
    shown = {n: state.get(n) for n in names}
    return ("Current shared state (read-only context):\n"
            + json.dumps(shown, ensure_ascii=False, default=str) + "\n\n")


_STATE_BLOCK_RE = re.compile(r"```state\s*\n(.*?)```", re.DOTALL | re.IGNORECASE)
_STATE_LINE_RE = re.compile(r"^([A-Za-z_]\w*)\s*(?:\+=|=)\s*(.+?)\s*$")


def _parse_state_value(raw: str):
    raw = raw.strip()
    try:
        return ast.literal_eval(raw)        # numbers, "strings", [lists], {dicts}, True/False
    except (ValueError, SyntaxError):
        return raw.strip("'\"")             # bare/unquoted text


def _split_state_block(raw: str):
    """Split a stage's output into (visible_text, {field: value}) by pulling out
    any trailing ```state ...``` block(s). Lines read `field = value` or
    `field += value`; the field's reducer (not the operator) decides the merge.
    Returns (raw, {}) when there's no block."""
    if not STATE_SCHEMA or "```state" not in raw.lower():
        return raw, {}
    updates = {}
    for m in _STATE_BLOCK_RE.finditer(raw):
        for line in m.group(1).splitlines():
            line = line.strip()
            if not line or line.startswith("#"):
                continue
            lm = _STATE_LINE_RE.match(line)
            if lm:
                updates[lm.group(1)] = _parse_state_value(lm.group(2))
    clean = _STATE_BLOCK_RE.sub("", raw).strip()
    return clean, updates


# ── deterministic control nodes: If/Else on state + state writes ─────────────
_COND_CMP = {
    ast.Lt: lambda a, b: a < b, ast.LtE: lambda a, b: a <= b,
    ast.Gt: lambda a, b: a > b, ast.GtE: lambda a, b: a >= b,
    ast.Eq: lambda a, b: a == b, ast.NotEq: lambda a, b: a != b,
    ast.In: lambda a, b: a in b, ast.NotIn: lambda a, b: a not in b,
}
_BIN_OP = {
    ast.Add: lambda a, b: a + b, ast.Sub: lambda a, b: a - b,
    ast.Mult: lambda a, b: a * b, ast.Div: lambda a, b: a / b,
    ast.FloorDiv: lambda a, b: a // b, ast.Mod: lambda a, b: a % b,
}


def _eval_ast(expr: str, env: dict):
    """Evaluate an allow-listed expression against `env` (name -> value) with NO
    eval. Supports comparisons, and/or/not, +,-,*,/,//,%, unary +/-, len() and
    literals. Names resolve from env; unknown names are None. Raises on anything
    outside the grammar."""
    def ev(node):
        if isinstance(node, ast.Expression):
            return ev(node.body)
        if isinstance(node, ast.BoolOp):
            vals = [ev(v) for v in node.values]
            return all(vals) if isinstance(node.op, ast.And) else any(vals)
        if isinstance(node, ast.UnaryOp):
            if isinstance(node.op, ast.Not):
                return not ev(node.operand)
            if isinstance(node.op, ast.USub):
                return -ev(node.operand)
            if isinstance(node.op, ast.UAdd):
                return +ev(node.operand)
            raise ValueError("unsupported unary op")
        if isinstance(node, ast.BinOp):
            fn = _BIN_OP.get(type(node.op))
            if fn is None:
                raise ValueError("unsupported binary op")
            return fn(ev(node.left), ev(node.right))
        if isinstance(node, ast.Compare):
            left = ev(node.left)
            for op, comp in zip(node.ops, node.comparators):
                right = ev(comp)
                fn = _COND_CMP.get(type(op))
                if fn is None or not fn(left, right):
                    return False
                left = right
            return True
        if isinstance(node, ast.Name):
            return env.get(node.id)
        if isinstance(node, ast.Constant):
            return node.value
        if (isinstance(node, ast.Call) and isinstance(node.func, ast.Name)
                and node.func.id == "len" and len(node.args) == 1):
            return len(ev(node.args[0]) or [])
        raise ValueError("unsupported expression element")
    return ev(ast.parse(expr, mode="eval"))


def _safe_eval(expr: str, state: dict) -> bool:
    """Boolean condition over `state` (no eval). False on any error."""
    try:
        return bool(_eval_ast(expr, state))
    except Exception:
        return False


def _setstate_apply(node: str, state: dict, carried: str, emit=print) -> dict:
    """Apply a setstate node's ordered assignments. Each value is a literal, or
    an '=expr' evaluated against the state plus `output` (the upstream text).
    Later assignments see earlier ones. Returns the applied {field: value}."""
    applied = {}
    for field, raw in SETSTATE.get(node, []):
        raw = (raw or "").strip()
        if raw.startswith("="):
            try:
                val = _eval_ast(raw[1:], dict(state, output=carried))
            except Exception as e:
                emit(f"[setstate] {node}: skipped {field} ({e})")
                continue
        else:
            val = _parse_state_value(raw)
        applied.update(_apply_state(state, {field: val}))
    return applied


def _eval_cond(node: str, state: dict, emit=print) -> str:
    """Pick a condition node's branch: the first whose expr is true (None = the
    else/fallback). Raises if nothing matches and there is no else."""
    for expr, target in CONDITIONS.get(node, []):
        if expr is None or _safe_eval(expr, state):
            emit(f"[condition] {node} -> {target}"
                 + ("" if expr is None else f"  ({expr})"))
            trace_event("condition", agent=node, choice=target,
                        expr=(expr or "else"))
            return target
    raise RuntimeError(f"condition '{node}' fell through with no else branch")


# ── enforced output contracts (validate a producer's output, retry, else stop) ──
class _ContractError(Exception):
    """A producer's output failed its ENFORCED output contract after all retries."""


def _extract_json(text):
    """Best-effort: parse the model's reply as a JSON object — the whole string, a
    ```json fenced block, or the first {...} span. None if nothing parses."""
    text = (text or "").strip()
    m = re.search(r"```(?:json)?\s*(\{.*\})\s*```", text, re.DOTALL)
    cand = m.group(1) if m else None
    if cand is None:
        i, j = text.find("{"), text.rfind("}")
        cand = text[i:j + 1] if 0 <= i < j else text
    try:
        obj = json.loads(cand)
    except Exception:
        return None
    return obj if isinstance(obj, dict) else None


def _contract_type_ok(t, v):
    if t == "int":
        return isinstance(v, int) and not isinstance(v, bool)
    if t == "float":
        return isinstance(v, (int, float)) and not isinstance(v, bool)
    if t == "bool":
        return isinstance(v, bool)
    if t == "list":
        return isinstance(v, list)
    if t == "dict":
        return isinstance(v, dict)
    return isinstance(v, str)                 # "str" / unknown -> require a string


def _validate_contract(fields, output):
    """(ok, reason). Output must be a JSON object with every declared field present
    and the right type. reason is model-facing feedback for the retry."""
    if not fields:
        return True, ""
    data = _extract_json(output)
    if data is None:
        return False, ("reply with ONLY a JSON object containing the fields: "
                       + ", ".join(f["name"] for f in fields))
    missing = [f["name"] for f in fields if f["name"] not in data]
    if missing:
        return False, "missing field(s): " + ", ".join(missing)
    bad = [f["name"] + " (must be " + f["type"] + ")"
           for f in fields if not _contract_type_ok(f["type"], data[f["name"]])]
    if bad:
        return False, "wrong type: " + ", ".join(bad)
    return True, ""


# ── structured final answer (opt-in agent final_schema; JSON-Schema subset) ──
def _json_type_ok(t, v):
    if t == "integer":
        return isinstance(v, int) and not isinstance(v, bool)
    if t == "number":
        return isinstance(v, (int, float)) and not isinstance(v, bool)
    if t == "boolean":
        return isinstance(v, bool)
    if t == "array":
        return isinstance(v, list)
    if t == "object":
        return isinstance(v, dict)
    if t == "null":
        return v is None
    if t == "string":
        return isinstance(v, str)
    return True             # unknown/absent type: no constraint


def _json_schema_check(schema, value, path="$"):
    """Validate `value` against a JSON-Schema SUBSET (type/properties/required/
    items/enum/additionalProperties). Returns (ok, reason)."""
    if not isinstance(schema, dict):
        return True, ""
    t = schema.get("type")
    if isinstance(t, str) and not _json_type_ok(t, value):
        return False, path + ": expected " + t
    if "enum" in schema and value not in schema["enum"]:
        return False, path + ": not one of " + repr(schema["enum"])
    if isinstance(value, dict):
        props = schema.get("properties") or {}
        for req in (schema.get("required") or []):
            if req not in value:
                return False, path + "." + req + ": required field missing"
        if schema.get("additionalProperties") is False:
            extra = [k for k in value if k not in props]
            if extra:
                return False, path + ": unexpected field(s) " + repr(extra)
        for k, sub in props.items():
            if k in value:
                ok, why = _json_schema_check(sub, value[k], path + "." + k)
                if not ok:
                    return False, why
    if isinstance(value, list) and isinstance(schema.get("items"), dict):
        for i, el in enumerate(value):
            ok, why = _json_schema_check(schema["items"], el, path + "[" + str(i) + "]")
            if not ok:
                return False, why
    return True, ""


def _validate_final_schema(schema, text):
    """(ok, reason, canonical). Parse `text` as a JSON object and validate it against
    `schema`. canonical = re-serialized object on success (fences/prose stripped),
    else the original text."""
    data = _extract_json(text)
    if data is None:
        return False, "reply with ONLY a JSON object matching the schema", text
    ok, why = _json_schema_check(schema, data)
    if not ok:
        return False, why, text
    return True, "", json.dumps(data, ensure_ascii=False)


def _run_stage_checked(name, question, emit):
    """Run a stage and split off its state block. Two optional gates, both re-run
    the stage with feedback (bounded):
    - require_writes: if the agent declared `writes` and `require_writes`, re-prompt
      until it records every field (via set_state or a ```state block), then proceed.
    - an ENFORCED output contract: validate the output as JSON, raising _ContractError
      if it never passes.
    Returns (output, upd)."""
    _rs().rec["written"] = set()                        # set_state writes recorded here
    raw = run_stage(name, question, emit)
    out, upd = _split_state_block(raw)
    _aspec = AGENTS.get(name, {})
    _req = (_aspec.get("writes") or []) if _aspec.get("require_writes") else []
    if _req:
        _tries, _n = 2, 0
        while True:
            _wrote = set(_rs().rec.get("written") or ()) | set((upd or {}).keys())
            _missing = [w for w in _req if w not in _wrote]
            if not _missing:
                break
            if _n >= _tries:
                emit("\n[require-writes] '%s' never recorded %s after %d attempt(s) "
                     "— proceeding." % (name, ", ".join(_missing), _n + 1))
                trace_event("require_writes", agent=name, ok=False, missing=_missing)
                break
            _n += 1
            emit("\n[require-writes] '%s' must record %s — retrying %d/%d"
                 % (name, ", ".join(_missing), _n, _tries))
            trace_event("require_writes", agent=name, ok=False, attempt=_n, missing=_missing)
            _rq = question + (
                "\n\n[You did NOT record required shared state. Call the set_state "
                "tool NOW to set: " + ", ".join(_missing) + ". Then continue.]")
            raw = run_stage(name, _rq, emit)       # _rs().rec['written'] accumulates
            _o2, _u2 = _split_state_block(raw)
            out, upd = _o2, {**(upd or {}), **(_u2 or {})}
    spec = CONTRACTS_OUT.get(name)
    if not spec:
        return out, upd
    fields = spec.get("fields") or []
    tries = int(spec.get("max_retries", 2) or 0)
    attempt = 0
    while True:
        ok, why = _validate_contract(fields, out)
        if ok:
            trace_event("contract", agent=name, ok=True, attempt=attempt)
            return out, upd
        if attempt >= tries:
            trace_event("contract", agent=name, ok=False, attempt=attempt, reason=why[:200])
            raise _ContractError(
                "[contract not met] agent '%s' output failed its output contract "
                "after %d attempt(s): %s" % (name, tries + 1, why))
        attempt += 1
        emit("\n[contract] '%s' output invalid (%s) — retrying %d/%d"
             % (name, why, attempt, tries))
        trace_event("contract", agent=name, ok=False, attempt=attempt, reason=why[:200])
        rq = question + (
            "\n\n[Your previous reply did NOT satisfy the required OUTPUT "
            "CONTRACT — " + why + ". Reply with ONLY a JSON object containing "
            "exactly the required fields, each correctly typed. No prose.]")
        raw = run_stage(name, rq, emit)
        out, upd = _split_state_block(raw)


def _join_merge(outputs, policy):
    """Combine the branch OUTPUT strings into the carried value after a join.
    concat (default) | first | last | state_only (branches spoke via shared state) |
    vote (majority / self-consistency: the most common branch output; ties -> the
    first branch). 'vote' matches on the STRIPPED text, so it's for constrained
    outputs (a label / number / short verdict) — free-form prose rarely ties, so a
    judge agent after a concat join is the right tool there."""
    outs = [str(o) for o in outputs if o is not None]
    if policy == "first":
        return outs[0] if outs else ""
    if policy == "last":
        return outs[-1] if outs else ""
    if policy == "state_only":
        return ""
    if policy == "vote":
        if not outs:
            return ""
        from collections import Counter
        counts = Counter(o.strip() for o in outs)   # 3.7+: ties keep insertion order
        winner = counts.most_common(1)[0][0]
        return next((o for o in outs if o.strip() == winner), outs[0])
    return "\n\n---\n\n".join(outs)


def _run_stage_budgeted(name, question, emit):
    """Run a stage honoring its on_budget policy for a [budget] result:
    'continue' (default) -> pass it downstream; 'retry' -> re-run up to stage_retries
    times (fresh budget); 'stop' (or retries exhausted) -> signal the caller to end
    the run. Returns (result, upd, stop) where stop=True means end the whole run with
    `result`. Shared by run_graph and run_pipeline."""
    result, upd = _run_stage_checked(name, question, emit)
    pol = AGENTS.get(name, {}).get("on_budget", "continue")
    _capped = lambda r: isinstance(r, str) and r.startswith("[budget]")
    if pol == "continue" or not _capped(result):
        return result, upd, False
    if pol == "retry":
        lim = int(AGENTS.get(name, {}).get("stage_retries", 0) or 0)
        n = 0
        while n < lim:
            n += 1
            emit("\n[budget] '%s' hit a budget — retrying %d/%d" % (name, n, lim))
            result, upd = _run_stage_checked(name, question, emit)
            if not _capped(result):
                return result, upd, False
    return result, upd, True     # stop (policy 'stop', or retries exhausted)


def _branch_run_state(parent, brec):
    """A per-branch _RunState: its OWN rec (isolated state / written / capture) and
    route / stream slots, but SHARING cancel / usage / cost / trace / HITL with the
    parent — so Stop propagates to every branch and usage/cost aggregate, while
    concurrent branches never clobber each other's state, written-set or route choice."""
    return _RunState(
        cancel=parent.cancel, stream={"obj": None}, rec=brec,
        cost=parent.cost, usage=parent.usage, route={"choice": None},
        ctx=parent.ctx, images=parent.images, confirm=parent.confirm,
        review=parent.review, allow=parent.allow, trace=parent.trace,
        lock=parent.lock, ws_skills=parent.ws_skills, session_id=parent.session_id)


def _merge_branch_builtins(parent_state, base_builtins, branch_state):
    """Fold a branch's built-in append lists (tool_calls / agents) into the parent by
    appending only what the branch ADDED beyond the FROZEN pre-join base. `base_builtins`
    MUST be a snapshot of the base lengths taken BEFORE the merge loop — not the live
    parent state — or branches after the first get diffed against an already-grown
    baseline and their entries are dropped (append-only, so the fixed-base diff is exact)."""
    for _f in ("tool_calls", "agents"):
        bl = branch_state.get(_f)
        if isinstance(bl, list):
            _extra = bl[len(base_builtins.get(_f) or []):]
            if _extra:
                parent_state[_f] = (parent_state.get(_f) or []) + _extra


def _run_branch(start, task, carried, base_state, stop_at, emit):
    """Run ONE fan-out branch: a linear chain of agent stages, on an ISOLATED fork of
    `base_state` (so concurrent branches don't race), stopping at the join (stop_at) or
    a stage with no successor. Returns (final_output, brec) where brec['capture'] is the
    ordered list of RAW (field, value) writes the branch made — the join replays those
    onto the parent via reducers (exact for append/add/max/min/concat)."""
    parent = _rs()
    brec = dict(parent.rec)
    brec["state"] = copy.deepcopy(base_state)
    brec["written"] = set()
    brec["capture"] = []                       # _apply_state records raw writes here
    _tok = _CURRENT_RUN.set(_branch_run_state(parent, brec))
    try:
        node = start
        out = carried
        for _ in range(RECURSION_LIMIT):
            if not node or node == stop_at:
                break
            if STAGE_KINDS.get(node) == "setstate":   # a Set-State step inside a branch
                _ap = _setstate_apply(node, brec["state"], out, emit)
                if _ap:
                    trace_event("state", agent=node, updates=_ap, state=dict(brec["state"]))
                _sc = SUCCESSORS.get(node, [])
                node = _sc[0] if _sc else None
                continue
            preamble = _state_preamble(brec["state"], AGENTS.get(node, {}).get("reads"))
            question = preamble + (
                f"Original task: {task}\n\nInput:\n{carried}\n\n"
                f"Continue according to your role.")
            _track_builtin("agents", node, agent=node)
            result, _upd = _run_stage_checked(node, question, emit)
            if _upd:
                _apply_state(brec["state"], _upd, AGENTS.get(node, {}).get("writes"))
            out = result
            _succ = SUCCESSORS.get(node, [])
            node = _succ[0] if _succ else None
        return out, brec
    finally:
        _CURRENT_RUN.reset(_tok)


def run_graph(task: str, emit=print, thread_id=None, entry=None) -> str:
    """Walk ENTRY -> successors; routers pick the branch, agents/pools run.
    A terminal stage that is the revise source (REVISE_EDGE) loops back to its
    target while it answers 'REVISE:' (bounded by MAX_REVISE_ROUNDS).

    `entry` overrides the start node (a stage NAME) — e.g. a schedule job that
    drives a specific agent starts the walk there instead of at ENTRY; None =
    ENTRY (byte-identical to a normal run).

    With checkpointing on (config + thread_id), the single-cursor loop locals are
    snapshotted at each stage boundary, so a stopped/crashed run resumes from the
    last stage (at-least-once per stage)."""
    node = entry or ENTRY
    carried = task
    ran_agent = False
    result = ""
    revise_rounds = 0
    _wcounts = {}                          # per-while-node iteration counts (max_iterations)
    state = _new_state(task)
    _ckpt_on = bool(CHECKPOINT_ENABLED and thread_id)
    if _ckpt_on:
        _snap = load_checkpoint(thread_id)
        if (_snap and not _snap.get("done")
                and _snap.get("topology_sig") == _TOPO_SIG):
            node = _snap.get("node") or ENTRY
            carried = _snap.get("carried", task)
            ran_agent = bool(_snap.get("ran_agent", False))
            revise_rounds = int(_snap.get("revise_rounds", 0) or 0)
            _wcounts = dict(_snap.get("while_counts") or {})
            state = _snap.get("state") if isinstance(_snap.get("state"), dict) else _new_state(task)
            emit(f"[checkpoint] resuming '{thread_id}' at {node}")
    _rs().rec["state"] = state              # built-in trackers reach state via _RUN
    for _hop in range(RECURSION_LIMIT):
        if not node:
            break
        _run_deadline_check()                # whole-run wall-clock deadline (raises)
        if _ckpt_on:
            save_checkpoint(thread_id, {
                "thread_id": thread_id, "agent_name": "badchatbot",
                "topology_sig": _TOPO_SIG, "task": task, "node": node,
                "carried": carried, "ran_agent": ran_agent,
                "revise_rounds": revise_rounds, "while_counts": _wcounts,
                "state": state,
                "hop": _hop, "done": False, "result": ""})
        kind = STAGE_KINDS.get(node)
        if kind == "end":                  # terminal sink: finish early
            if _ckpt_on:                   # clear FIRST so a raising emit/trace can't
                clear_checkpoint(thread_id)  # leave a dirty checkpoint (done=False)
            emit(f"\n[end] reached '{node}' — finishing early.")
            trace_event("end", agent=node)
            return carried                 # the output carried into End (post-guardrail)
        if kind == "router":
            node = route(node, carried, emit)
            continue
        if kind == "hitl":      # route mode: a human picks which branch runs next
            node, carried = _human_route(node, carried, emit)
            continue
        if kind == "while":     # a guard->body/else->exit loop
            _cap = int(CONFIG.get("while_max_iterations", {}).get(node, 0) or 0)
            if _cap:
                _wcounts[node] = _wcounts.get(node, 0) + 1
                if _wcounts[node] > _cap:
                    emit(f"\n[while] {node} hit max_iterations={_cap} — taking exit")
                    trace_event("while_limit", agent=node, limit=_cap)
                    node = next((t for e, t in CONDITIONS.get(node, []) if e is None), None)
                    continue
            node = _eval_cond(node, state, emit)
            continue
        if kind == "condition":
            node = _eval_cond(node, state, emit)
            continue
        if kind == "setstate":
            _applied = _setstate_apply(node, state, carried, emit)
            if _applied:
                trace_event("state", agent=node, updates=_applied, state=dict(state))
            _succ = SUCCESSORS.get(node, [])
            node = _succ[0] if _succ else None
            continue
        if kind == "guardrail":
            carried, _blocked, _why = guardrail_node_apply(GUARDRAIL_NODES.get(node, {}), carried)
            trace_event("guardrail", where="node", agent=node,
                        action=("block" if _blocked else "redact"))
            if _blocked:
                emit(f"\n[guardrail] {node} stopped the flow ({_why}).")
                return f"[blocked by guardrail] content was stopped at '{node}' ({_why})."
            _succ = SUCCESSORS.get(node, [])
            node = _succ[0] if _succ else None
            continue
        if kind == "fanout":               # run branches CONCURRENTLY, join = barrier
            from concurrent.futures import ThreadPoolExecutor
            _fo = FANOUT.get(node, {})
            _join = _fo.get("join")
            _branches = _fo.get("branches", [])
            emit(f"\n=== [{node}] fan-out: {len(_branches)} branches in parallel ===")
            trace_event("fanout", agent=node, branches=_branches, join=_join)
            _base = state                     # each branch forks its OWN copy of this
            # FROZEN pre-join lengths of the built-in append lists — so each branch's
            # additions are diffed against the SAME base (not a growing alias of state).
            _base_builtins = {_f: list(state.get(_f) or [])
                              for _f in ("tool_calls", "agents")}
            _cap_n = int(_fo.get("max_parallel", 0) or 0) or len(_branches)
            _res = [None] * len(_branches)
            # carry this run into each worker via a FRESH context copy per branch (one
            # Context can't be entered by two threads); _run_branch forks a per-branch
            # RunState inside so their states never collide.
            with ThreadPoolExecutor(max_workers=max(1, min(_cap_n, len(_branches)))) as _ex:
                _futs = {_ex.submit(contextvars.copy_context().run,
                                    _run_branch, _b, task, carried, _base, _join, emit): _i
                         for _i, _b in enumerate(_branches)}
                for _f in _futs:
                    _i = _futs[_f]
                    try:
                        _res[_i] = _f.result()
                    except RunCancelled:
                        for _o in _futs:         # a Stop aborts the whole fan-out
                            _o.cancel()
                        raise
                    except Exception as _e:      # fault isolation: one branch failing
                        _res[_i] = (f"[ERROR] branch '{_branches[_i]}' failed: {_e}",
                                    {"state": {}, "capture": []})
            # JOIN barrier: replay each branch's RAW writes onto the shared state in
            # declaration order (deterministic), + fold built-in append lists.
            _outs = []
            for _out, _brec in _res:
                _outs.append(_out)
                for _field, _raw in _brec.get("capture", []):
                    _apply_state(state, {_field: _raw})
                _merge_branch_builtins(state, _base_builtins, _brec.get("state", {}))
            trace_event("join", agent=_join, branches=_branches, state=dict(state))
            carried = _join_merge(_outs, JOIN.get(_join, {}).get("merge", "concat"))
            ran_agent = True
            _jsucc = SUCCESSORS.get(_join, [])
            node = _jsucc[0] if _jsucc else None            # continue after the join
            continue
        if kind == "join":                 # reached directly (defensive) — pass through
            _succ = SUCCESSORS.get(node, [])
            node = _succ[0] if _succ else None
            continue
        if kind == "foreach":              # map: run `body` once per item of state[over]
            from concurrent.futures import ThreadPoolExecutor
            _fe = FOREACH.get(node, {})
            _over = _fe.get("over", "")
            _body = _fe.get("body")
            _exit = _fe.get("exit")
            _ivar = _fe.get("item_var", "")
            _rfield = _fe.get("result_field", "")
            _items = state.get(_over)
            if not isinstance(_items, list):    # tolerate a stray scalar / empty field
                _items = [] if _items in (None, "", {}) else [_items]
            emit(f"\n=== [{node}] for-each '{_over}': {len(_items)} item(s) in parallel ===")
            trace_event("foreach", agent=node, over=_over, count=len(_items), body=_body)
            # FROZEN pre-loop built-in lengths — each item's additions diff against this.
            _base_builtins = {_f: list(state.get(_f) or [])
                              for _f in ("tool_calls", "agents")}
            _cap_n = int(_fe.get("max_parallel", 0) or 0) or (len(_items) or 1)
            _res = [None] * len(_items)
            if _items:
                # each item forks an ISOLATED state (item passed BOTH as the body's input
                # AND, when item_var is set, written into that state field); one fresh
                # context copy per item (a Context can't be entered by two threads).
                with ThreadPoolExecutor(max_workers=max(1, min(_cap_n, len(_items)))) as _ex:
                    _futs = {}
                    for _i, _item in enumerate(_items):
                        _fork_base = {**state, _ivar: _item} if _ivar else state
                        _futs[_ex.submit(contextvars.copy_context().run,
                                         _run_branch, _body, task, _item,
                                         _fork_base, node, emit)] = _i
                    for _f in _futs:
                        _i = _futs[_f]
                        try:
                            _res[_i] = _f.result()
                        except RunCancelled:
                            for _o in _futs:        # a Stop aborts the whole map
                                _o.cancel()
                            raise
                        except Exception as _e:     # fault isolation: one item failing
                            _res[_i] = (f"[ERROR] item {_i} failed: {_e}",
                                        {"state": {}, "capture": []})
            # collect: replay each item's RAW writes via reducers, fold built-ins,
            # and (optionally) append each item's OUTPUT into result_field.
            _outs = []
            for _out, _brec in _res:
                _outs.append(_out)
                for _field, _raw in _brec.get("capture", []):
                    _apply_state(state, {_field: _raw})
                _merge_branch_builtins(state, _base_builtins, _brec.get("state", {}))
                if _rfield:
                    _apply_state(state, {_rfield: _out})
            trace_event("foreach_done", agent=node, count=len(_outs), state=dict(state))
            carried = _join_merge(_outs, _fe.get("merge", "concat"))
            ran_agent = True
            node = _exit                          # continue after the loop
            continue
        preamble = _state_preamble(state, AGENTS.get(node, {}).get("reads"))
        question = preamble + (carried if not ran_agent else (
            f"Original task: {task}\n\nInput:\n{carried}\n\n"
            f"Continue according to your role."))
        _track_builtin("agents", node, agent=node)   # built-in: agent visited
        try:
            # run + (if this stage has an ENFORCED output contract) validate & retry;
            # _stop_budget honors the agent's on_budget policy on a [budget] result.
            result, _upd, _stop_budget = _run_stage_budgeted(node, question, emit)
        except _ContractError as e:               # never satisfied -> stop the run
            if _ckpt_on:
                clear_checkpoint(thread_id)
            emit("\n" + str(e))
            return str(e)
        if _stop_budget:
            if _ckpt_on:
                clear_checkpoint(thread_id)
            emit("\n[budget] '%s' exceeded its budget — stopping the run." % node)
            return result
        if _upd:
            _applied = _apply_state(state, _upd, AGENTS.get(node, {}).get("writes"))
            if _applied:
                trace_event("state", agent=node, updates=_applied, state=dict(state))
        ran_agent = True
        succ = SUCCESSORS.get(node, [])
        if not succ:
            if (REVISE_EDGE and node == REVISE_EDGE[0]
                    and result.strip().upper().startswith("REVISE")
                    and revise_rounds < MAX_REVISE_ROUNDS):
                revise_rounds += 1
                emit(f"\n=== Revise round {revise_rounds}: back to "
                     f"{REVISE_EDGE[1]} ===")
                carried = result
                node = REVISE_EDGE[1]
                continue
            if _ckpt_on:
                clear_checkpoint(thread_id)
            return result
        carried = result
        if AGENTS.get(node, {}).get("route_self") and len(succ) > 1:
            quick = bool(AGENTS.get(node, {}).get("quick_response"))
            chosen = _rs().route.get("choice")
            if quick and chosen == QUICK_RESPONSE:   # planner declined to hand off
                emit(f"[route] {node} (self) -> (quick response, no branch)")
                trace_event("route", router=node, choice=QUICK_RESPONSE,
                            routes=succ)
                if _ckpt_on:
                    clear_checkpoint(thread_id)
                return result                        # end with the planner's answer
            if chosen in succ:                       # planner used the route_to tool
                emit(f"[route] {node} (self) -> {chosen}")
                node, carried = chosen, result
            else:                                    # text-line 'ROUTE:' fallback
                node, carried = _self_route(node, result, succ, emit, quick=quick)
                if quick and node == QUICK_RESPONSE:  # declined via 'ROUTE: __none__'
                    if _ckpt_on:
                        clear_checkpoint(thread_id)
                    return carried                   # cleaned planner answer
        else:
            node = succ[0]  # non-router stages have exactly one successor
    else:
        raise GraphRecursionError(
            f"graph exceeded recursion_limit={RECURSION_LIMIT} stage transitions "
            f"(stuck near '{node}'?). A Condition loop's exit expression may never "
            "become true — fix it, or raise the loop limit in "
            "Graph -> Edit Shared State.")
    if _ckpt_on:
        clear_checkpoint(thread_id)
    return result or "[graph] no terminal stage reached."


def run_pipeline(task: str, emit=print, entry=None) -> str:
    feedback = ""
    result = ""
    state = _new_state(task)
    _rs().rec["state"] = state
    # `entry` (a stage NAME) starts the chain partway through — a schedule job
    # that drives a specific agent runs that agent and everything downstream of
    # it. None (or an unknown name) = the whole pipeline (byte-identical).
    _pipe = PIPELINE
    if entry and entry in PIPELINE:
        _pipe = PIPELINE[PIPELINE.index(entry):]
    try:
        for round_no in range(MAX_REVISE_ROUNDS + 1):
            prev_name, prev_out = None, ""
            for agent_name in _pipe:
                preamble = _state_preamble(state, AGENTS.get(agent_name, {}).get("reads"))
                if prev_name is None:
                    question = preamble + task + feedback
                else:
                    question = (
                        preamble
                        + f"Original task: {task}\n\n"
                        + f"Output from previous agent ({prev_name}):\n{prev_out}\n\n"
                        + f"Continue according to your role."
                    )
                _track_builtin("agents", agent_name, agent=agent_name)
                # run + (contract validate/retry) + on_budget policy
                prev_out, _upd, _stop_budget = _run_stage_budgeted(agent_name, question, emit)
                if _stop_budget:
                    emit("\n[budget] '%s' exceeded its budget — stopping the run."
                         % agent_name)
                    return prev_out
                if _upd:
                    _applied = _apply_state(
                        state, _upd, AGENTS.get(agent_name, {}).get("writes"))
                    if _applied:
                        trace_event("state", agent=agent_name,
                                    updates=_applied, state=dict(state))
                prev_name = agent_name
            result = prev_out
            if REVISE_EDGE and result.strip().upper().startswith("REVISE"):
                emit(f"\n=== Revise round {round_no + 1}: looping back to "
                     f"{REVISE_EDGE[1]} ===")
                feedback = f"\n\nReviewer feedback to address:\n{result}"
                continue
            break
    except _ContractError as e:                # a stage's output never satisfied its contract
        emit("\n" + str(e))
        return str(e)
    return result


def run_supervisor(task: str, emit=print) -> str:
    """Supervisor delegates one instruction per round until it says DONE."""
    supervisor, workers = PIPELINE[0], PIPELINE[1:]
    state = _new_state(task)
    _rs().rec["state"] = state
    log = f"Task: {task}"
    out = "(no worker output)"
    for round_no in range(1, MAX_SUPERVISOR_ROUNDS + 1):
        _track_builtin("agents", supervisor, agent=supervisor)
        sup = react(
            supervisor,
            _state_preamble(state, AGENTS.get(supervisor, {}).get("reads"))
            + log + "\n\nReply with 'NEXT: <instruction>' "
                  "(or 'NEXT <worker_name>: <instruction>') to delegate the "
                  "next step, or 'DONE: <final answer>' when complete. "
                  f"Workers: {', '.join(workers)}.",
            emit)
        s = sup.strip()
        if s.upper().startswith("DONE"):
            return s.split(":", 1)[-1].strip() if ":" in s else s
        target, instr = workers[0], s
        m = re.match(r"NEXT\s+(\w+)\s*:\s*(.*)", s, re.IGNORECASE | re.DOTALL)
        if m and m.group(1) in workers:
            target, instr = m.group(1), m.group(2)
        else:
            m = re.match(r"NEXT\s*:\s*(.*)", s, re.IGNORECASE | re.DOTALL)
            if m:
                instr = m.group(1)
        _wq = (_state_preamble(state, AGENTS.get(target, {}).get("reads"))
               + f"Original task: {task}\n\n"
               + f"Supervisor instruction:\n{instr}")
        _track_builtin("agents", target, agent=target)
        _raw = run_stage(target, _wq, emit)
        out, _upd = _split_state_block(_raw)
        if _upd:
            _applied = _apply_state(state, _upd, AGENTS.get(target, {}).get("writes"))
            if _applied:
                trace_event("state", agent=target, updates=_applied, state=dict(state))
        log += (f"\n\n[supervisor -> {target}]: {instr}"
                f"\n[{target} result]: {out}")
        emit(f"\n=== Supervisor round {round_no} done ===")
    return out


def run_autonomous(task: str, emit=print) -> str:
    """Autonomous mode: the orchestrator (ENTRY) runs once and delegates to its
    sub-agents through the built-in spawn_subagent tool (each an isolated react),
    then synthesizes their results itself."""
    state = _new_state(task)
    _rs().rec["state"] = state
    _q = _state_preamble(state, AGENTS.get(ENTRY, {}).get("reads")) + task
    _track_builtin("agents", ENTRY, agent=ENTRY)
    _raw = run_stage(ENTRY, _q, emit)
    result, _upd = _split_state_block(_raw)
    if _upd:
        _applied = _apply_state(state, _upd, AGENTS.get(ENTRY, {}).get("writes"))
        if _applied:
            trace_event("state", agent=ENTRY, updates=_applied, state=dict(state))
    return result


def mode_command(task: str):
    """Parse a leading /mode [label] command. Returns (cleaned_task, label):
    label is '' for a bare /mode (report request), the requested label, or None
    when the task is not a /mode command."""
    m = re.match(r"\s*/mode\b\s*([A-Za-z0-9_-]+)?\s*(.*)", task or "", re.DOTALL)
    if not m:
        return task, None
    return m.group(2), (m.group(1) or "").strip()


def _modes_hint() -> str:
    cur = ACTIVE_MODE or DEFAULT_LABEL or PATTERN_MODE
    return (f"[mode] current: {cur} | available: "
            + (", ".join(sorted(MODES)) if MODES else "(none)")
            + " — switch with /mode <label>")


def _run_for(name, question, emit, thread_id, entry=None):
    """Invoke the runner for a pattern/mode name (run_graph alone threads
    thread_id). One ladder, shared by both _dispatch_run branches. `entry` (a
    start-stage NAME, used by schedule jobs that drive a specific agent) is
    honoured by the pipeline/graph runners; supervisor/autonomous always start
    at their canonical head."""
    if name == "supervisor":
        return run_supervisor(question, emit)
    if name == "graph":
        return run_graph(question, emit, thread_id=thread_id, entry=entry)
    if name == "autonomous":
        return run_autonomous(question, emit)
    return run_pipeline(question, emit, entry=entry)


_MODE_LOCK = threading.Lock()   # serialize the multi-pattern topology-globals swap


def _dispatch_run(question, emit, thread_id, entry=None):
    """Pick the runner. With a MODES table, route by the active label and swap
    that mode's topology globals around the matching runner; otherwise take the
    legacy PATTERN_MODE path (byte-identical for single-pattern apps). `entry` (a
    start-stage NAME) lets a schedule job drive a specific agent."""
    if MODES:
        spec = MODES.get(ACTIVE_MODE or DEFAULT_LABEL) or next(iter(MODES.values()))
        # The swap MUTATES module-level topology globals for the duration of the
        # run, so concurrent multi-pattern runs must be serialized or they'd clobber
        # each other's topology. Single-pattern apps (MODES={}) skip this path and
        # run fully concurrently. (Multi-pattern + high concurrency is a rare combo;
        # here correctness wins over parallelism.)
        with _MODE_LOCK:
            g, saved = globals(), {}
            for _k, _v in (spec.get("globals") or {}).items():
                saved[_k] = g.get(_k)
                g[_k] = _v
            try:
                return _run_for(spec.get("runner"), question, emit, thread_id, entry)
            finally:
                for _k, _v in saved.items():
                    g[_k] = _v
    return _run_for(PATTERN_MODE, question, emit, thread_id, entry)


def run(task: str, emit=print, on_token=None, images=None, thread_id=None,
        session_id=None, on_confirm=None, on_review=None, image_parts=None,
        entry=None) -> str:
    """Uniform entry point (also used by the GUI / websocket).

    `entry` (a stage NAME) starts the run at a specific agent instead of ENTRY —
    used by schedule jobs so several schedule nodes can each drive a DIFFERENT
    agent in one graph. None = start at ENTRY (byte-identical).

    `session_id` binds this turn to its OWN conversation + run state (cancel,
    usage, cost, images, HITL, workspace) so simultaneous web / gateway users run
    CONCURRENTLY without sharing anything. Blank = the default single active
    session (GUI / CLI), byte-for-byte today's behaviour. `on_confirm(tool, args)`
    / `on_review(prompt, content)` are per-run HITL handlers (the web server passes
    its browser bridge here, since a forked run has its own handler slot — a global
    set_confirm_handler would race across concurrent connections). When session_id
    is set a fresh _RunState is forked into the ContextVar (propagated to pool
    workers), registered for targeted Stop, and reset in `finally`."""
    if not session_id:
        return _run_inner(task, emit, on_token, images, thread_id, image_parts, entry)
    _st = _RunState.fresh(session_id)
    if on_confirm is not None:
        _st.confirm["fn"] = on_confirm       # per-connection bridge (not shared)
    if on_review is not None:
        _st.review["fn"] = on_review
    with _ACTIVE_RUNS_LOCK:
        _ACTIVE_RUNS[session_id] = _st       # so request_cancel(session_id) finds it
    _tok = _CURRENT_RUN.set(_st)
    try:
        return _run_inner(task, emit, on_token, images, thread_id, image_parts, entry)
    finally:
        _CURRENT_RUN.reset(_tok)
        with _ACTIVE_RUNS_LOCK:
            if _ACTIVE_RUNS.get(session_id) is _st:
                _ACTIVE_RUNS.pop(session_id, None)


def _run_inner(task: str, emit=print, on_token=None, images=None,
               thread_id=None, image_parts=None, entry=None) -> str:
    """The actual run, executed against the CURRENT run state (_rs()) — the forked
    per-session state under run(session_id=…), else the process default.

    `on_token(delta)` receives live text deltas for serial stages (parallel
    pool workers run on other threads without the sink, so they don't
    interleave). `images` is an optional list of image FILE paths attached to
    the user's turn (sent to the entry agent if its model is a vision model);
    the web UI stages pre-encoded parts via set_run_image_parts() instead.
    Prepends stored context, dispatches by PATTERN_MODE, persists the exchange,
    and writes a JSONL trace under traces/."""
    _TOK.on_token = on_token
    _rs().cancel.clear()                          # fresh run; clear any prior Stop
    reset_confirm_session()                  # fresh run; forget "don't ask again"
    _rs().rec["nonce"] = os.urandom(4).hex()      # fresh untrusted-tag token per run
    if images is not None:                   # desktop attach: encode file paths
        set_run_images(images)
    if image_parts:                          # web attach: pre-encoded parts, staged
        set_run_image_parts(image_parts)     #   INTO this (possibly forked) run state
    had_images = bool(_rs().images)          # for a clearer error if the model
                                             # turns out not to accept images
    start_trace(task)
    _mcp_ensure_started(emit)
    _u0 = total_usage()                      # to report this run's delta
    with _USAGE_LOCK:                        # tool-call budget is PER RUN, not
        for _u in _rs().usage.values():            # cumulative-per-process — otherwise a
            _u["tool_calls"] = 0             # long-lived GUI/server would silently
                                             # starve pool workers across runs.
        _rs().cost["usd"] = 0.0               # cost cap is per-run too
    compact_history(_summarize_overflow)     # fold overflow into the summary
    if "refresh_workspace_skills" in globals():
        refresh_workspace_skills()           # discover <workspace>/.*/skills/*/SKILL.md
    # user-invoked pattern switch: a leading /mode <label> selects the runner for
    # this turn (sticky thereafter). Bare /mode (or a switch with no follow-up
    # task) just reports the current + available modes.
    if MODES:
        task, _mlabel = mode_command(task)
        if _mlabel is not None:
            if _mlabel and _mlabel in MODES:
                globals()["ACTIVE_MODE"] = _mlabel
            elif _mlabel:
                emit(f"[mode] unknown mode '{_mlabel}'. {_modes_hint()}")
            if not task.strip():
                msg = _modes_hint()
                emit(msg)
                set_run_image_parts([])          # don't leak staged images to the
                trace_event("run_end", result=msg, usage=_rs().usage)  # next (other-session) run
                return msg
    # user-invoked skill: a leading /<skill-name> loads that skill's full body
    # into this turn (the raw task is still what gets traced/stored/guarded).
    task_eff = skill_command(task) if "skill_command" in globals() else task
    question = history_context() + task_eff   # history_context() is "" when empty
    # opt-in input guardrail (OFF by default; weak — see guardrail_scan_input)
    _gin = guardrail_scan_input(task, AGENTS.get(ENTRY, {}).get("guardrails"))
    if _gin:
        emit(f"\n[guardrail] {_gin}")
        set_run_image_parts([])                  # don't leak staged images onward
        trace_event("run_end", result=_gin, usage=_rs().usage)
        return _gin
    completed = True
    _rs().rec["run_start"] = time.monotonic()   # baseline for max_run_wall_clock_s
    try:
        result = _dispatch_run(question, emit, thread_id, entry)
    except HumanRejected as e:               # a HITL 'stop' rejection
        result = str(e)
        completed = False
        emit(f"\n[HITL] {result}")
    except RunCancelled as e:                # the user pressed Stop
        result = str(e)
        completed = False
        emit(f"\n{result}")
    except Exception as e:                   # provider/network error — finish
        result = f"[error] {type(e).__name__}: {e}"   # cleanly, don't hang
        completed = False
        if had_images and (_is_image_error(e) or "All " in str(e)):
            result += ("\n[hint] You attached an image — this model may not "
                       "support image input. Turn off 'Accepts image input' "
                       "on its LLM node, or pick a vision-capable model.")
        emit(f"\n{result}")
        trace_event("run_error", error=str(e), had_images=had_images)
    set_run_image_parts([])                  # never carry images to the next run
    # Persist only a completed exchange — a cancelled / rejected / errored /
    # budget-capped run shouldn't leave a synthetic reply that re-enters the
    # next run's context.
    if completed and not result.startswith("[budget]"):
        record_turn(task, result)            # forked session buffer, or default
    _u1 = total_usage()
    di, do = (_u1["input_tokens"] - _u0["input_tokens"],
              _u1["output_tokens"] - _u0["output_tokens"])
    note = "" if (di or do) else "  (provider didn't report token usage)"
    ctx = context_usage()                    # entry-agent context window
    if ctx.get("capacity"):
        ctx_str = ("  |  context: ~{:.1f}k / {}k".format(
            ctx["tokens"] / 1000, ctx["capacity"] // 1000))
    elif ctx.get("tokens"):
        ctx_str = "  |  context: ~{:.1f}k".format(ctx["tokens"] / 1000)
    else:
        ctx_str = ""
    emit(f"[usage] this run: {di} in + {do} out tokens  |  session: "
         f"{_u1['input_tokens']} in + {_u1['output_tokens']} out{note}{ctx_str}")
    trace_event("run_end", result=result, usage=_rs().usage)
    emit(f"[trace] {_rs().trace['path']}")
    return result


def resume(thread_id: str, emit=print) -> str:
    """Continue a checkpointed graph-mode run from where it stopped. Re-enters
    run_graph with the saved task; run_graph rehydrates the cursor + state from
    the checkpoint. Returns a notice if there is no live checkpoint to resume."""
    snap = load_checkpoint(thread_id) if CHECKPOINT_ENABLED else None
    if not snap or snap.get("done"):
        return f"[checkpoint] nothing to resume for '{thread_id}'."
    _rs().cancel.clear()
    _rs().rec["run_start"] = time.monotonic()   # deadline restarts on resume
    reset_confirm_session()                  # don't inherit a prior run's "don't
                                             # ask again" allowance on resume
    try:
        return run_graph(snap.get("task", ""), emit, thread_id=thread_id)
    except RunCancelled as e:                # incl. RunDeadline → return its message
        return str(e)


# ── eval harness: grade the agent against eval sets (Pillar 1) ──────────────
# Eval sets are runtime-editable from the GUI's "Evals -> Edit Eval Sets..."
# menu. Defaults come from the canvas Eval node(s) (config['evals']) or the
# evals/*.jsonl files; GUI edits persist to evals.json and override the
# defaults — so an Eval node may be left empty in the canvas and filled in here.
EVALSETS_PATH = os.path.join(BASE_DIR, "evals.json")


def _default_eval_sets() -> list:
    sets = [dict(s) for s in (CONFIG.get("evals", []) or [])]
    if sets:
        return sets
    for rel in ("evals/evalset.jsonl", "evals/evalset.example.jsonl"):
        path = os.path.join(BASE_DIR, rel)
        if os.path.isfile(path):
            with open(path, encoding="utf-8") as f:
                cases = [json.loads(line) for line in f if line.strip()]
            return [{"name": "evalset", "target": None, "cases": cases}]
    return []


def _load_eval_sets() -> list:
    try:
        with open(EVALSETS_PATH, encoding="utf-8") as f:
            data = json.load(f)
        if isinstance(data, list):
            return data
    except (OSError, json.JSONDecodeError):
        pass
    return _default_eval_sets()


EVAL_SETS = _load_eval_sets()


def save_eval_sets() -> None:
    try:
        with open(EVALSETS_PATH, "w", encoding="utf-8") as f:
            json.dump(EVAL_SETS, f, indent=2, ensure_ascii=False)
    except OSError:
        pass


def eval_targets() -> list:
    """Agent names a set may target (a set with target None tests the whole
    pipeline; single-agent builds have no sub-targets)."""
    return list(PIPELINE) if "PIPELINE" in globals() else []


def add_eval_set(name: str, target=None) -> None:
    EVAL_SETS.append({"name": (name or "").strip() or f"set{len(EVAL_SETS) + 1}",
                      "target": target or None, "cases": []})
    save_eval_sets()


def update_eval_set(index: int, name: str, target=None) -> None:
    if 0 <= index < len(EVAL_SETS):
        EVAL_SETS[index]["name"] = (name or "").strip() or EVAL_SETS[index]["name"]
        EVAL_SETS[index]["target"] = target or None
        save_eval_sets()


def remove_eval_set(index: int) -> None:
    if 0 <= index < len(EVAL_SETS):
        EVAL_SETS.pop(index)
        save_eval_sets()


def add_eval_case(set_index: int, case: dict) -> None:
    if 0 <= set_index < len(EVAL_SETS):
        EVAL_SETS[set_index].setdefault("cases", []).append(case)
        save_eval_sets()


def update_eval_case(set_index: int, case_index: int, case: dict) -> None:
    if 0 <= set_index < len(EVAL_SETS):
        cases = EVAL_SETS[set_index].setdefault("cases", [])
        if 0 <= case_index < len(cases):
            cases[case_index] = case
            save_eval_sets()


def remove_eval_case(set_index: int, case_index: int) -> None:
    if 0 <= set_index < len(EVAL_SETS):
        cases = EVAL_SETS[set_index].setdefault("cases", [])
        if 0 <= case_index < len(cases):
            cases.pop(case_index)
            save_eval_sets()


def _eval_run_input(target, task):
    """Run one case: the whole pipeline (target None) or one agent in isolation."""
    if target and "AGENTS" in globals() and target in AGENTS:
        return react(target, task, lambda s: None)
    return run(task, emit=lambda s: None)


def eval_judge(target, task, answer, criterion) -> bool:
    """LLM grader for free-form answers: does `answer` satisfy `criterion`?"""
    system = "You are a strict grader. Reply with ONLY 'YES' or 'NO'."
    prompt = (f"Criterion: {criterion}\n\nTask:\n{task}\n\nAnswer:\n"
              f"{answer}\n\nDoes the answer satisfy the criterion? "
              "Reply YES or NO.")
    try:
        if "PIPELINE" in globals():
            name = (target if (target and "AGENTS" in globals()
                               and target in AGENTS) else PIPELINE[0])
            text, _ = llm(name, system,
                          [{"role": "user", "content": prompt}], lambda s: None)
        else:
            text, _ = _llm_once(system, [{"role": "user", "content": prompt}])
    except Exception:
        return False
    return (text or "").strip().upper().startswith("Y")


# ── grader registry (dependency-free; stdlib only) ──────────────────────────
# A case is graded by one or more typed assertions. Modern form:
#   {"type": "contains", "value": "...", "case_sensitive": false}      # single
#   {"checks": [{...}, {...}], "match": "all"|"any"}                   # multiple
# Legacy form (still works, same precedence as before): expected_output /
# expected_regex / judge. Borrows the assertion taxonomy of promptfoo /
# LangChain / DeepEval, minus checks that need heavy deps (embeddings/BLEU/ROUGE).
def _g_norm(s, a):
    s = str(s).strip()
    return s if a.get("case_sensitive") else s.lower()


def _g_list(value):
    if isinstance(value, list):
        return [str(x).strip() for x in value if str(x).strip()]
    return [p.strip() for p in re.split(r"[,\n]", str(value or "")) if p.strip()]


def _g_num(s):
    m = re.search(r"-?\d+(?:\.\d+)?", str(s))
    return float(m.group()) if m else None


def _g_json(ans):
    try:
        return json.loads(ans)
    except Exception:
        pass
    m = re.search(r"\{.*\}|\[.*\]", ans or "", re.DOTALL)   # first JSON-ish blob
    if m:
        try:
            return json.loads(m.group())
        except Exception:
            return None
    return None


def _g_contains(ans, a, ctx):
    v = a.get("value", "")
    return bool(str(v).strip()) and _g_norm(v, a) in _g_norm(ans, a)


def _g_similar(ans, a, ctx):
    import difflib
    thr = float(a.get("threshold", 0.8) or 0.8)
    return difflib.SequenceMatcher(
        None, _g_norm(ans, a), _g_norm(a.get("value", ""), a)).ratio() >= thr


def _g_numeric(ans, a, ctx):
    got, want = _g_num(ans), _g_num(a.get("value"))
    if got is None or want is None:
        return False
    return abs(got - want) <= float(a.get("tolerance", 0) or 0)


def _g_length(ans, a, ctx):
    n = len(ans or "")
    lo, hi = a.get("min"), a.get("max")
    return ((lo is None or n >= int(lo)) and (hi is None or n <= int(hi)))


def _g_regex(ans, a, ctx):
    flags = 0 if a.get("case_sensitive") else re.IGNORECASE
    try:
        return bool(re.search(a.get("value", ""), ans or "", flags))
    except re.error:
        return False


_GRADERS = {
    "equals": lambda ans, a, ctx: _g_norm(ans, a) == _g_norm(a.get("value", ""), a),
    "contains": _g_contains,
    "icontains": _g_contains,
    "not_contains": lambda ans, a, ctx: not _g_contains(ans, a, ctx),
    "contains_all": lambda ans, a, ctx: bool(_g_list(a.get("value")))
        and all(_g_norm(x, a) in _g_norm(ans, a) for x in _g_list(a.get("value"))),
    "contains_any": lambda ans, a, ctx:
        any(_g_norm(x, a) in _g_norm(ans, a) for x in _g_list(a.get("value"))),
    "starts_with": lambda ans, a, ctx: _g_norm(ans, a).startswith(_g_norm(a.get("value", ""), a)),
    "ends_with": lambda ans, a, ctx: _g_norm(ans, a).endswith(_g_norm(a.get("value", ""), a)),
    "regex": _g_regex,
    "not_regex": lambda ans, a, ctx: not _g_regex(ans, a, ctx),
    "is_json": lambda ans, a, ctx: _g_json(ans) is not None,
    "json_has_keys": lambda ans, a, ctx: isinstance(_g_json(ans), dict)
        and all(k in _g_json(ans) for k in _g_list(a.get("value"))),
    "numeric": _g_numeric,
    "close": _g_numeric,
    "similar": _g_similar,
    "length": _g_length,
    "llm_rubric": lambda ans, a, ctx: eval_judge(
        ctx.get("target"), ctx.get("task", ""), ans, a.get("value", "")),
}
# friendly aliases
_GRADERS["exact"] = _GRADERS["equals"]
_GRADERS["judge"] = _GRADERS["llm_rubric"]
_GRADERS["rubric"] = _GRADERS["llm_rubric"]


def _run_assertion(ans, a, ctx) -> bool:
    fn = _GRADERS.get(str(a.get("type", "")).strip().lower())
    if fn is None:
        return False
    try:
        ok = bool(fn(ans, a, ctx))
    except Exception:
        ok = False
    return (not ok) if a.get("not") else ok        # per-assertion negation


def _case_assertions(case) -> list:
    """Normalize a case into a list of typed assertions. Legacy single-field
    cases keep their exact old precedence (judge > regex > contains = one
    assertion)."""
    if isinstance(case.get("checks"), list):
        return [c for c in case["checks"] if isinstance(c, dict) and c.get("type")]
    if case.get("type"):
        return [{k: v for k, v in case.items() if k not in ("id", "input")}]
    if case.get("judge"):
        return [{"type": "llm_rubric", "value": case["judge"]}]
    if case.get("expected_regex"):
        return [{"type": "regex", "value": case["expected_regex"]}]
    if case.get("expected_output"):
        return [{"type": "contains", "value": case["expected_output"]}]
    return []


def grade(case, answer, target=None) -> bool:
    ans = answer or ""
    assertions = _case_assertions(case)
    if not assertions:
        return False                          # no expectation declared = fail
    ctx = {"task": case.get("input", ""), "target": target}
    results = [_run_assertion(ans, a, ctx) for a in assertions]
    return (any(results) if str(case.get("match", "all")).lower() == "any"
            else all(results))


def run_evals(emit=print) -> list:
    """Run every eval set; returns [{name,target,passed,total,score}]. Disables
    history persistence and auto-approves HITL so it runs unattended."""
    global save_history, SUMMARY, record_turn
    _orig_save = save_history
    save_history = lambda: None
    # record_turn is the append+persist path run() uses now — it bypasses
    # save_history, so neutralize it too or evals would pollute the conversation.
    _orig_record = record_turn
    record_turn = lambda task, result: None
    _orig_hist = list(HISTORY) if "HISTORY" in globals() else None
    _orig_summary = SUMMARY if "SUMMARY" in globals() else None
    if "SUMMARY" in globals():
        SUMMARY = ""                      # isolate eval from any stored summary
    if "set_confirm_handler" in globals():
        set_confirm_handler(lambda tool_name, args: True)   # eval auto-allows
    if "set_review_handler" in globals():
        set_review_handler(lambda prompt, content: {
            "decision": "approve", "content": content, "feedback": ""})
    if "_CANCEL" in globals():
        _CANCEL.clear()
    results = []
    try:
        sets = EVAL_SETS
        if not sets:
            emit("[eval] no eval sets — add one via 'Evals -> Edit Eval "
                 "Sets...', an Eval node, or evals/evalset.jsonl")
            return results
        for s in sets:
            target = s.get("target")
            cases = [c for c in (s.get("cases", []) or [])
                     if (c.get("input") or "").strip()]
            emit(f"[eval] {s['name']} \u2192 {target or 'whole pipeline'} "
                 f"({len(cases)} case(s))")
            if not cases:
                emit("  (no cases yet — add some via 'Edit Eval Sets...')")
                results.append({"name": s["name"], "target": target,
                                "passed": 0, "total": 0, "score": 0.0})
                continue
            passed = 0
            for c in cases:
                if "HISTORY" in globals():
                    HISTORY[:] = []
                try:
                    ans = _eval_run_input(target, c.get("input", ""))
                except Exception as e:
                    ans = f"[crash] {type(e).__name__}: {e}"
                ok = grade(c, ans, target)
                passed += int(ok)
                # Show the FULL response (grading already uses it in full); a
                # truncated preview here hid why a case passed/failed.
                shown = (ans or "").strip() or "(empty response)"
                emit(f"  [{'PASS' if ok else 'FAIL'}] {c.get('id', '?')}: {shown}")
            score = passed / len(cases) if cases else 0.0
            emit(f"[eval] {s['name']}: {passed}/{len(cases)} = {score:.2f}")
            results.append({"name": s["name"], "target": target,
                            "passed": passed, "total": len(cases),
                            "score": score})
    finally:
        save_history = _orig_save
        record_turn = _orig_record
        if _orig_hist is not None:        # never pollute the live conversation
            HISTORY[:] = _orig_hist
        if _orig_summary is not None:     # ...nor the rolling summary
            SUMMARY = _orig_summary
    return results


def main() -> None:
    args = sys.argv[1:]
    if args and args[0] == "--new":
        clear_history()
        args = args[1:]
    if HISTORY:
        print(f"(resuming {len(HISTORY) // 2} earlier exchange(s); "
              "run with --new to start fresh)")
    tok = lambda d: (sys.stdout.write(d), sys.stdout.flush())
    task = " ".join(args).strip()
    if task:
        result = run(task, on_token=tok)
        print(f"\n\n=== Final Result ===\n{result}")
        return
    print("badchatbot — type a task, or 'exit' to quit.")
    while True:
        try:
            task = input("\nYou: ").strip()
        except (EOFError, KeyboardInterrupt):
            break
        if not task or task.lower() in ("exit", "quit"):
            break
        result = run(task, on_token=tok)
        print(f"\n\n=== Final Result ===\n{result}")


if __name__ == "__main__":
    main()
